import{_ as e,c as t,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Ключевые функции: Три возможности | opencode-dcp","description":"Изучите три ключевые функции opencode-dcp: автоматические стратегии обрезки, инструменты на базе LLM и команды Slash. Освойте эти функции для полного использования потенциала оптимизации токенов.","frontmatter":{"title":"Ключевые функции: Три возможности | opencode-dcp","sidebarTitle":"Три ключевые возможности","subtitle":"Ключевые функции: Три возможности","description":"Изучите три ключевые функции opencode-dcp: автоматические стратегии обрезки, инструменты на базе LLM и команды Slash. Освойте эти функции для полного использования потенциала оптимизации токенов.","order":20},"headers":[],"relativePath":"ru/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md","filePath":"ru/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md"}'),s={name:"ru/Opencode-DCP/opencode-dynamic-context-pruning/platforms/index.md"};function l(r,a,i,d,c,p){return o(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="ключевые-функции" tabindex="-1">Ключевые функции <a class="header-anchor" href="#ключевые-функции" aria-label="Permalink to &quot;Ключевые функции&quot;">​</a></h1><p>В этой главе подробно рассматриваются три ключевые возможности DCP: автоматические стратегии обрезки, инструменты на базе LLM и команды Slash. Освоив эти функции, вы сможете в полной мере использовать потенциал DCP для оптимизации токенов.</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><div class="grid-cards"><h3 id="автоматические-стратегии-обрезки" tabindex="-1"><a href="./auto-pruning/">Автоматические стратегии обрезки</a> <a class="header-anchor" href="#автоматические-стратегии-обрезки" aria-label="Permalink to &quot;[Автоматические стратегии обрезки](./auto-pruning/)&quot;">​</a></h3><p>Глубокое понимание работы трёх автоматических стратегий DCP: стратегия дедупликации, стратегия перезаписи и стратегия очистки ошибок. Узнайте условия срабатывания и сценарии применения каждой стратегии.</p><h3 id="инструменты-обрезки-на-базе-llm" tabindex="-1"><a href="./llm-tools/">Инструменты обрезки на базе LLM</a> <a class="header-anchor" href="#инструменты-обрезки-на-базе-llm" aria-label="Permalink to &quot;[Инструменты обрезки на базе LLM](./llm-tools/)&quot;">​</a></h3><p>Поймите, как ИИ самостоятельно вызывает инструменты <code>discard</code> и <code>extract</code> для оптимизации контекста. Это самая интеллектуальная функция DCP, позволяющая ИИ активно участвовать в управлении контекстом.</p><h3 id="использование-команд-slash" tabindex="-1"><a href="./commands/">Использование команд Slash</a> <a class="header-anchor" href="#использование-команд-slash" aria-label="Permalink to &quot;[Использование команд Slash](./commands/)&quot;">​</a></h3><p>Освойте все команды DCP: <code>/dcp context</code> для просмотра состояния контекста, <code>/dcp stats</code> для просмотра статистики, <code>/dcp sweep</code> для ручного запуска обрезки.</p></div><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Рекомендуется изучать содержание этой главы в следующем порядке:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Автоматические стратегии обрезки → Инструменты на базе LLM → Команды Slash</span></span>
<span class="line"><span>↓                      ↓                      ↓</span></span>
<span class="line"><span>Понимание принципов    Освоение интеллектуальной обрезки    Изучение мониторинга и отладки</span></span></code></pre></div><ol><li><strong>Сначала изучите автоматические стратегии обрезки</strong>: это основа DCP, поймите принцип работы трёх стратегий</li><li><strong>Затем изучите инструменты на базе LLM</strong>: после понимания автоматических стратегий изучите более продвинутые возможности активной обрезки ИИ</li><li><strong>Наконец, изучите команды Slash</strong>: освойте методы мониторинга и ручного управления для удобной отладки и оптимизации</li></ol><div class="tip custom-block"><p class="custom-block-title">Предварительные условия</p><p>Перед изучением этой главы убедитесь, что вы завершили:</p><ul><li><a href="./../start/getting-started/">Установку и быстрый старт</a> — установка плагина DCP</li><li><a href="./../start/configuration/">Полное руководство по конфигурации</a> — понимание основных концепций системы конфигурации</li></ul></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете продолжить изучение:</p><ul><li><strong><a href="./../advanced/protection/">Механизмы защиты</a></strong> — узнайте, как защитить критически важный контент от случайной обрезки</li><li><strong><a href="./../advanced/state-persistence/">Персистентность состояния</a></strong> — поймите, как DCP сохраняет состояние между сессиями</li><li><strong><a href="./../advanced/prompt-caching/">Влияние на кэширование промптов</a></strong> — разберитесь в компромиссах между DCP и кэшированием промптов</li></ul>`,12)])])}const m=e(s,[["render",l]]);export{u as __pageData,m as default};
